import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import '../styles/RecordingIndicators.css';

function RecordingIndicators() {
  const navigate = useNavigate();
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [indicatorsData, setIndicatorsData] = useState([]);
  const [isEditing, setIsEditing] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [newRecord, setNewRecord] = useState({
    date: '',
    fev1: '',
    fvc: '',
    pef: '',
    respiratoryRate: '',
    pulse: '',
    cough: '',
    breathlessness: '',
    wheezing: '',
    chestTightness: '',
    nighttimeAwakenings: '',
    medicine: ''
  });

  useEffect(() => {
    const user_id = localStorage.getItem('user_id');
    if (!user_id) {
      navigate('/');
      return;
    }

    const fetchRecords = async () => {
      try {
        const response = await fetch(`http://localhost:5000/api/health-records/${user_id}`);
        if (!response.ok) {
          throw new Error('Failed to fetch records');
        }
        const data = await response.json();
        setIndicatorsData(data);
      } catch (error) {
        console.error('Error fetching records:', error);
        setError('Failed to load records');
      }
    };

    fetchRecords();
  }, [navigate]);

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setNewRecord(prev => ({
      ...prev,
      [name]: value
    }));
    setError(''); // Clear any previous errors
  };

  const validateRecord = () => {
    const requiredFields = [
      'date', 'fev1', 'fvc', 'pef', 'respiratoryRate', 'pulse',
      'cough', 'breathlessness', 'wheezing', 'chestTightness',
      'nighttimeAwakenings', 'medicine'
    ];

    const emptyFields = requiredFields.filter(field => !newRecord[field]);
    if (emptyFields.length > 0) {
      setError('Please fill in all fields');
      return false;
    }

    // Validate numeric fields
    const numericFields = ['fev1', 'fvc', 'pef', 'respiratoryRate', 'pulse', 'nighttimeAwakenings'];
    for (const field of numericFields) {
      if (isNaN(newRecord[field])) {
        setError(`${field} must be a number`);
        return false;
      }
    }

    return true;
  };

  const handleSaveRecord = async () => {
    if (!validateRecord()) {
      return;
    }

    setError('');
    setSuccess('');

    const user_id = localStorage.getItem('user_id');
    if (!user_id) {
      navigate('/');
      return;
    }

    try {
      const response = await fetch('http://localhost:5000/api/health-records', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          ...newRecord,
          user_id: parseInt(user_id)
        }),
      });

      if (!response.ok) {
        throw new Error('Failed to add record');
      }

      // Refresh records
      const recordsResponse = await fetch(`http://localhost:5000/api/health-records/${user_id}`);
      const recordsData = await recordsResponse.json();
      setIndicatorsData(recordsData);
      setSuccess('Record added successfully');

      // Reset the form
      setNewRecord({
        date: '',
        fev1: '',
        fvc: '',
        pef: '',
        respiratoryRate: '',
        pulse: '',
        cough: '',
        breathlessness: '',
        wheezing: '',
        chestTightness: '',
        nighttimeAwakenings: '',
        medicine: ''
      });
      setIsEditing(false);
    } catch (err) {
      setError(err.message);
    }
  };

  const handleAddNewRow = () => {
    setIsEditing(true);
  };

  const handleLogout = () => {
    localStorage.removeItem('user_id');
    navigate('/');
  };

  const toggleSidebar = () => {
    setIsSidebarOpen(!isSidebarOpen);
  };

  return (
    <div className={`recording-indicators-container ${isSidebarOpen ? 'sidebar-open' : ''}`}>
      <div className="top-bar">
        <div className="top-center">
          <h1>Asthma Monitoring</h1>
        </div>
        <div className="nav-buttons">
          <button onClick={handleLogout} className="logout-button">
            Logout
          </button>
        </div>
      </div>
      <div className="content">
        <h2>Recording Indicators</h2>
        {error && <div className="error-message">{error}</div>}
        {success && <div className="success-message">{success}</div>}

        <div className="table-container">
          <table className="indicators-table">
            <thead>
              <tr>
                <th>Date</th>
                <th>FEV1</th>
                <th>FVC</th>
                <th>PEF</th>
                <th>Respiratory Rate</th>
                <th>Pulse</th>
                <th>Cough</th>
                <th>Breathlessness</th>
                <th>Wheezing</th>
                <th>Chest Tightness</th>
                <th>Nighttime Awakenings</th>
                <th>Medicine</th>
              </tr>
            </thead>
            <tbody>
              {indicatorsData.map((row, index) => (
                <tr key={index}>
                  <td>{new Date(row.date).toLocaleDateString()}</td>
                  <td>{row.fev1}</td>
                  <td>{row.fvc}</td>
                  <td>{row.pef}</td>
                  <td>{row.respiratoryRate}</td>
                  <td>{row.pulse}</td>
                  <td>{row.cough}</td>
                  <td>{row.breathlessness}</td>
                  <td>{row.wheezing}</td>
                  <td>{row.chestTightness}</td>
                  <td>{row.nighttimeAwakenings}</td>
                  <td>{row.medicine}</td>
                </tr>
              ))}
              {isEditing && (
                <tr className="editing-row">
                  <td>
                    <input
                      type="date"
                      name="date"
                      value={newRecord.date}
                      onChange={handleInputChange}
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      name="fev1"
                      value={newRecord.fev1}
                      onChange={handleInputChange}
                      placeholder="FEV1"
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      name="fvc"
                      value={newRecord.fvc}
                      onChange={handleInputChange}
                      placeholder="FVC"
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      name="pef"
                      value={newRecord.pef}
                      onChange={handleInputChange}
                      placeholder="PEF"
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      name="respiratoryRate"
                      value={newRecord.respiratoryRate}
                      onChange={handleInputChange}
                      placeholder="Rate"
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      name="pulse"
                      value={newRecord.pulse}
                      onChange={handleInputChange}
                      placeholder="Pulse"
                    />
                  </td>
                  <td>
                    <select
                      name="cough"
                      value={newRecord.cough}
                      onChange={handleInputChange}
                    >
                      <option value="">Select</option>
                      <option value="None">None</option>
                      <option value="Mild">Mild</option>
                      <option value="Moderate">Moderate</option>
                      <option value="Severe">Severe</option>
                    </select>
                  </td>
                  <td>
                    <select
                      name="breathlessness"
                      value={newRecord.breathlessness}
                      onChange={handleInputChange}
                    >
                      <option value="">Select</option>
                      <option value="None">None</option>
                      <option value="Mild">Mild</option>
                      <option value="Moderate">Moderate</option>
                      <option value="Severe">Severe</option>
                    </select>
                  </td>
                  <td>
                    <select
                      name="wheezing"
                      value={newRecord.wheezing}
                      onChange={handleInputChange}
                    >
                      <option value="">Select</option>
                      <option value="None">None</option>
                      <option value="Mild">Mild</option>
                      <option value="Moderate">Moderate</option>
                      <option value="Severe">Severe</option>
                    </select>
                  </td>
                  <td>
                    <select
                      name="chestTightness"
                      value={newRecord.chestTightness}
                      onChange={handleInputChange}
                    >
                      <option value="">Select</option>
                      <option value="None">None</option>
                      <option value="Mild">Mild</option>
                      <option value="Moderate">Moderate</option>
                      <option value="Severe">Severe</option>
                    </select>
                  </td>
                  <td>
                    <input
                      type="number"
                      name="nighttimeAwakenings"
                      value={newRecord.nighttimeAwakenings}
                      onChange={handleInputChange}
                      placeholder="Times"
                    />
                  </td>
                  <td>
                    <input
                      type="text"
                      name="medicine"
                      value={newRecord.medicine}
                      onChange={handleInputChange}
                      placeholder="Medicine"
                    />
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
        <div className="button-container">
          {!isEditing && (
            <button onClick={handleAddNewRow} className="add-row-button">
              Add New Row
            </button>
          )}
          {isEditing && (
            <button onClick={handleSaveRecord} className="save-row-button">
              Save Record
            </button>
          )}
        </div>
      </div>

      <div className={`sidebar ${isSidebarOpen ? 'open' : ''}`}>
        <div className="sidebar-header">
          <h2>Menu</h2>
        </div>
        <nav className="sidebar-nav">
          <button onClick={() => navigate('/dashboard')}>
            Home
          </button>
          <button onClick={() => navigate('/recording-indicators')}>
            Recording Indicators
          </button>
          <button onClick={() => navigate('/exacerbation-forecast')}>
            Exacerbation Forecast
          </button>
          <button onClick={() => navigate('/graphs-of-changes')}>
            Graphs of Changes
          </button>
          <button onClick={() => navigate('/medication-diary')}>
            Medication Diary
          </button>
        </nav>
      </div>
      <div className="floating-menu-button" onClick={toggleSidebar}>
        <span></span>
        <span></span>
        <span></span>
      </div>
    </div>
  );
}

export default RecordingIndicators;
